sp_css.css:
/*
Collection of CSS that is used in Out of Office

2.8.1 | 2022-09-21| raj  |  STRY0130635 - Task Form- Assignee is Out of Office

ANY CHANGES MADE IN THIS FILE ALSO NEED TO BE MADE IN the local stylesheet file "tasker-out-of-office-native-ui.css" for the platform/native ui to stay in sync. 
you can find that file in ../content_css_list.do

*/
.dtech-ooo-list-message-item{
    padding:2px;
}

.dtech-ooo-message-text{
  color:#92386F;
  font-size:14px;
}

.dtech-ooo-message-container{
  padding:10px;
  background-color: #f4f4f4;
  border-radius: 0px 0px 5px 5px;
  cursor: pointer;
}

.dtech-ooo-background-color{
  background-color: #f4f4f4;
}

.dtech-ooo-pad-right-10{
  padding-right:10px;
  cursor: pointer;
}

.dtech-ooo-tooltip-html {
  max-width: 400px !important;
  background-color:#FFFFFF;
  color:#000000;
  font-size:14px;
}

.dtech-ooo-arrow-up:before {
  border-bottom: 10px solid $tasker-popover-arrow-color;
  border-left: 10px solid transparent;
  border-right: 10px solid transparent;
  content: '';
  height: 0;
  left: calc(100% / 2 - 10px);
  position: absolute;
  top: -10px;
  width: 0;
  z-index: 2;
}

.dtech-ooo-arrow-up:after {
  border-bottom: 12px solid rgba(0, 0, 0, 0.1);
  border-left: 12px solid transparent;
  border-right: 12px solid transparent;
  content: '';
  height: 0;
  left: calc(100% / 2 - 12px);
  position: absolute;
  top: -12px; 
  width: 0;
  z-index: 1;
}

.dtech-ooo-tooltip-container{
  background-color: $tasker-popover-container-avatar-color;
  border-radius: 5px;
  padding: 10px 10px 10px 10px;
  left: -200px;
  position: absolute;
  width: 400px;
  box-shadow: 0px 0px 20px 0px rgba(0, 0, 0, 0.25);
  -webkit-box-shadow: 0px 0px 20px 0px rgba(0, 0, 0, 0.25);
  -moz-box-shadow: 0px 0px 20px 0px rgba(0, 0, 0, 0.25);
}
